import{_ as a,c as i,o as t,ak as s,aq as r}from"./chunks/framework.DHLlVITf.js";const p=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v3-1-0.md","filePath":"aireblock-releases/aireframe-v3-1-0.md","lastUpdated":1784108722000}'),o={name:"aireblock-releases/aireframe-v3-1-0.md"};function n(l,e,c,d,h,u){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+r+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 3.1.0<br><strong>Release Date:</strong> 15 July 2026</p></blockquote><h4 id="🚨-critical-fixes" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h4><ul><li>Fixed Dashboard Switching on iPad and Mobile (FRAME-2461)</li><li>Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569)</li></ul><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Subject Banner Display Options from the Subject Launcher (FRAME-2589)</li><li>Smarter Multi-Subject View Updates (FRAME-2594)</li><li>Streamlined Data Extracts Table (FRAME-2602)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Faster Data Visualisations (FRAME-2556)</li><li>Smarter Subject List Refresh Notifications (FRAME-2567)</li><li>Live Update Indicators for Structural Entity Widgets (FRAME-2575)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Delayed Permission Updates (FRAME-2584)</li><li>Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619)</li><li>Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="🚨-critical-fixes-1" tabindex="-1">🚨 Critical Fixes <a class="header-anchor" href="#🚨-critical-fixes-1" aria-label="Permalink to “🚨 Critical Fixes”">​</a></h3><hr><h4 id="fixed-dashboard-switching-on-ipad-and-mobile-frame-2461" tabindex="-1">Fixed Dashboard Switching on iPad and Mobile (FRAME-2461) <a class="header-anchor" href="#fixed-dashboard-switching-on-ipad-and-mobile-frame-2461" aria-label="Permalink to “Fixed Dashboard Switching on iPad and Mobile (FRAME-2461)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where users on iPad and other mobile devices could not switch back to the original dashboard after selecting a different one on a subject record.</p></div><h4 id="fixed-visualisations-getting-stuck-mid-update-frame-2569" tabindex="-1">Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569) <a class="header-anchor" href="#fixed-visualisations-getting-stuck-mid-update-frame-2569" aria-label="Permalink to “Fixed Visualisations Getting Stuck Mid-Update (FRAME-2569)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a fault where visualisations could become permanently stuck in a pending state if a data set update job failed without triggering a retry, leaving the visualisation refresh unresolved.</p></div><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="subject-banner-display-options-from-the-subject-launcher-frame-2589" tabindex="-1">Subject Banner Display Options from the Subject Launcher (FRAME-2589) <a class="header-anchor" href="#subject-banner-display-options-from-the-subject-launcher-frame-2589" aria-label="Permalink to “Subject Banner Display Options from the Subject Launcher (FRAME-2589)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The subject launcher now supports the <code>subjectBanner=hidden</code>, <code>subjectBanner=collapsed</code> and <code>subjectBanner=expanded</code> query parameters, matching existing behaviour on the subject view.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now control whether the subject banner is shown, hidden, or collapsed when launching directly into a subject.</p></div><h4 id="smarter-multi-subject-view-updates-frame-2594" tabindex="-1">Smarter Multi-Subject View Updates (FRAME-2594) <a class="header-anchor" href="#smarter-multi-subject-view-updates-frame-2594" aria-label="Permalink to “Smarter Multi-Subject View Updates (FRAME-2594)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Improved stale subject tracking in the multi-subject view so it no longer flags subjects that aren&#39;t part of the active list, and clears stale tracking correctly when navigating between pages.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll see fewer unnecessary refreshes and more accurate &quot;out of date&quot; indicators when browsing subject lists.</p></div><h4 id="streamlined-data-extracts-table-frame-2602" tabindex="-1">Streamlined Data Extracts Table (FRAME-2602) <a class="header-anchor" href="#streamlined-data-extracts-table-frame-2602" aria-label="Permalink to “Streamlined Data Extracts Table (FRAME-2602)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Removed the &quot;used by data pipelines&quot; column from the Data Extracts table, as this information is now covered by the existing &quot;in use&quot; column.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your Data Extracts table is now simpler and free of duplicate information.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="faster-data-visualisations-frame-2556" tabindex="-1">Faster Data Visualisations (FRAME-2556) <a class="header-anchor" href="#faster-data-visualisations-frame-2556" aria-label="Permalink to “Faster Data Visualisations (FRAME-2556)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Subject list and table visualisations now updated faster and more efficiently and continue to display available data when the subjects at a location change.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your visualisations will load faster and stay more up to date as your data changes.</p></div><h4 id="smarter-subject-list-refresh-notifications-frame-2567" tabindex="-1">Smarter Subject List Refresh Notifications (FRAME-2567) <a class="header-anchor" href="#smarter-subject-list-refresh-notifications-frame-2567" aria-label="Permalink to “Smarter Subject List Refresh Notifications (FRAME-2567)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Reworked how the multi-subject list handles incoming data updates. Rather than refreshing automatically and potentially disrupting filtering or ordering, the list now shows a notification with a manual refresh option, plus a per-session toggle for automatic refresh.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll no longer lose your place in a subject list when new data arrives. You&#39;ll see a clear notice when updates are available and can choose when to refresh, with an option to turn automatic refreshing back on if you prefer it.</p></div><h4 id="live-update-indicators-for-structural-entity-widgets-frame-2575" tabindex="-1">Live Update Indicators for Structural Entity Widgets (FRAME-2575) <a class="header-anchor" href="#live-update-indicators-for-structural-entity-widgets-frame-2575" aria-label="Permalink to “Live Update Indicators for Structural Entity Widgets (FRAME-2575)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Added subscription support for pending update events on structural entity widgets, building on the reworked notification handling introduced elsewhere in this release.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Structural entity widgets will more accurately reflect when their underlying data has changed.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-delayed-permission-updates-frame-2584" tabindex="-1">Fixed Delayed Permission Updates (FRAME-2584) <a class="header-anchor" href="#fixed-delayed-permission-updates-frame-2584" aria-label="Permalink to “Fixed Delayed Permission Updates (FRAME-2584)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where changes to a user&#39;s role were not reflected in AireFrame in a timely manner, sometimes requiring an overnight cache invalidation before the correct permissions took effect.</p></div><h4 id="fixed-subject-lists-not-refreshing-when-marked-stale-frame-2619" tabindex="-1">Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619) <a class="header-anchor" href="#fixed-subject-lists-not-refreshing-when-marked-stale-frame-2619" aria-label="Permalink to “Fixed Subject Lists Not Refreshing When Marked Stale (FRAME-2619)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where the subject list did not refresh when the underlying data was marked as stale.</p></div><h4 id="fixed-dashboard-reloading-and-forms-closing-on-widget-updates-frame-2628" tabindex="-1">Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628) <a class="header-anchor" href="#fixed-dashboard-reloading-and-forms-closing-on-widget-updates-frame-2628" aria-label="Permalink to “Fixed Dashboard Reloading and Forms Closing on Widget Updates (FRAME-2628)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where a widget update sometimes caused the whole page to reload, closing any open forms.</p></div>',47)])])}const b=a(o,[["render",n]]);export{p as __pageData,b as default};
